/**
 * Dev.to Widget
 *
 * Shows latest articles from Dev.to
 */

import React, { useState, useEffect, useCallback } from 'react';
import { BaseWidget } from './BaseWidget';
import { useWidgetStore } from '../../stores/useWidgetStore';

interface DevToArticle {
  title: string;
  url: string;
  user: {
    name: string;
  };
  positive_reactions_count: number;
  comments_count: number;
  published_at: string;
}

export const DevToWidget: React.FC = () => {
  const [articles, setArticles] = useState<DevToArticle[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const refreshRate = useWidgetStore((state) => state.widgetSettings.devto?.refreshRate);

  const fetchArticles = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      const response = await fetch('https://dev.to/api/articles?per_page=5&top=7');
      if (!response.ok) throw new Error('Failed to fetch Dev.to articles');

      const data = await response.json();
      setArticles(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load articles');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchArticles();
  }, [fetchArticles]);

  useEffect(() => {
    if (!refreshRate) return;

    const interval = setInterval(() => {
      fetchArticles();
    }, refreshRate * 60 * 1000);

    return () => clearInterval(interval);
  }, [refreshRate, fetchArticles]);

  return (
    <BaseWidget
      title="Dev.to Articles"
      icon="📝"
      loading={loading}
      error={error}
      onRefresh={fetchArticles}
    >
      {articles.length > 0 && (
        <div className="space-y-3">
          {articles.map((article, index) => (
            <a
              key={index}
              href={article.url}
              target="_blank"
              rel="noopener noreferrer"
              className="block p-2 rounded hover:bg-neutral-100 dark:hover:bg-neutral-800 transition-all duration-standard ease-smooth"
            >
              <h4 className="font-medium text-sm text-text-light-primary dark:text-text-dark-primary line-clamp-2 mb-1">
                {article.title}
              </h4>
